esqlQuery.esql:
FROM metrics-vcenterreceiver.otel-*
// Host disk latency max (ms): healthy <15ms; unhealthy >30ms
// Uses max latency per object; use vcenter.host.disk.latency.avg if available for finer granularity
// Adjust threshold to suit storage tier
| WHERE vcenter.host.disk.latency.max IS NOT NULL AND vcenter.host.disk.latency.max > 15
| STATS latency_ms = MAX(vcenter.host.disk.latency.max) BY vcenter.datacenter.name, vcenter.cluster.name, vcenter.host.name, attributes.object
| SORT latency_ms DESC
| LIMIT 20
